package sn.gestionimmobiliere.backend.lease.api;
import java.net.URI;import java.time.LocalDate;import java.util.UUID;import org.springframework.data.domain.*;import org.springframework.data.web.PageableDefault;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.*;import io.swagger.v3.oas.annotations.tags.Tag;import jakarta.validation.Valid;import sn.gestionimmobiliere.backend.lease.application.LeaseService;
@RestController @RequestMapping("/api/leases") @Tag(name="Leases") public class LeaseController{private final LeaseService service;public LeaseController(LeaseService s){service=s;}@PostMapping public ResponseEntity<LeaseResponse> create(@Valid @RequestBody CreateLeaseRequest r){LeaseResponse l=service.create(r);return ResponseEntity.created(URI.create("/api/leases/"+l.id())).body(l);}@GetMapping public Page<LeaseResponse> all(@PageableDefault(size=20,sort="startDate")Pageable p){return service.all(p);}@GetMapping("/{id}")public LeaseResponse one(@PathVariable UUID id){return service.one(id);}@PostMapping("/{id}/terminate")public LeaseResponse terminate(@PathVariable UUID id,@RequestParam LocalDate date){return service.terminate(id,date);}}
